Consistent hash ring with one point per physical node — no virtual nodes, no incremental `add_node`/`remove_node`.

```python
import hashlib
import bisect
from dataclasses import dataclass

KEYS = [f"key-{i:05d}" for i in range(10_000)]

def stable_hash(key: str) -> int:
    return int(hashlib.md5(key.encode()).hexdigest(), 16)

@dataclass(frozen=True)
class Ring:
    _positions: tuple[int, ...]
    _owners: tuple[str, ...]

    @classmethod
    def build(cls, nodes: list[str]) -> "Ring":
        pts = sorted((stable_hash(node), node) for node in nodes)
        return cls(tuple(p for p, _ in pts), tuple(o for _, o in pts))

    def get_node(self, key: str) -> str:
        idx = bisect.bisect(self._positions, stable_hash(key)) % len(self._positions)
        return self._owners[idx]

ring3 = Ring.build(["node-a", "node-b", "node-c"])
ring4 = Ring.build(["node-a", "node-b", "node-c", "node-d"])

add_plan = [
    {"key": k, "from": ring3.get_node(k), "to": ring4.get_node(k)}
    for k in KEYS if ring3.get_node(k) != ring4.get_node(k)
]
rem_plan = [
    {"key": k, "from": ring4.get_node(k), "to": ring3.get_node(k)}
    for k in KEYS if ring4.get_node(k) != ring3.get_node(k)
]

print(f"add 3→4: {len(add_plan)} keys ({100*len(add_plan)/len(KEYS):.1f}%)")
print(f"rem 4→3: {len(rem_plan)} keys ({100*len(rem_plan)/len(KEYS):.1f}%)")
```

Why bad: one hash point per node skews ownership — some nodes hold far more than 1/N keys. Rebuilding the whole ring on every change works for a demo but gives no incremental migration API and no cutover plan scoped to the joining or departing node. Production rings use virtual nodes (128+ per physical node) for even spread.

Consistent hash ring with virtual nodes; rebuild ring for add, rebuild without removed node for remove.

```python
import hashlib
import bisect
from dataclasses import dataclass

KEYS = [f"key-{i:05d}" for i in range(10_000)]
VNODE_COUNT = 128

def stable_hash(key: str) -> int:
    return int(hashlib.md5(key.encode()).hexdigest(), 16)

@dataclass(frozen=True)
class Ring:
    _positions: tuple[int, ...]
    _owners: tuple[str, ...]

    @classmethod
    def build(cls, nodes: list[str], vnodes: int = VNODE_COUNT) -> "Ring":
        pts = []
        for node in nodes:
            for i in range(vnodes):
                pts.append((stable_hash(f"{node}#{i}"), node))
        pts.sort()
        return cls(tuple(p for p, _ in pts), tuple(o for _, o in pts))

    def get_node(self, key: str) -> str:
        idx = bisect.bisect(self._positions, stable_hash(key)) % len(self._positions)
        return self._owners[idx]

def migration_plan(before: Ring, after: Ring) -> list[dict]:
    return [
        {"key": k, "from": before.get_node(k), "to": after.get_node(k)}
        for k in KEYS if before.get_node(k) != after.get_node(k)
    ]

ring3 = Ring.build(["node-a", "node-b", "node-c"])
ring4 = Ring.build(["node-a", "node-b", "node-c", "node-d"])
add_plan = migration_plan(ring3, ring4)
rem_plan = migration_plan(ring4, ring3)

print(f"add 3→4: {len(add_plan)} keys ({100*len(add_plan)/len(KEYS):.1f}%)")
print(f"rem 4→3: {len(rem_plan)} keys ({100*len(rem_plan)/len(KEYS):.1f}%)")
print(f"rem from node-d only: {sum(1 for m in rem_plan if m['from'] == 'node-d')}")
```

Good: both directions move ~25% of keys. On remove, every migration has `from == 'node-d'` — you only copy keys that actually lived on the failed node; keys on a/b/c stay put.

Limitation: rebuilds entire ring instead of incremental `add_node`/`remove_node`; no cutover handling for in-flight requests.
